// Extrai e calcula métricas
const data = $input.first().json.data;

if (!data || data.length === 0) {
  return [{ json: { sem_dados: true } }];
}

const d = data[0];
const spend = parseFloat(d.spend || 0);
const impressions = parseInt(d.impressions || 0);
const clicks = parseInt(d.clicks || 0);
const ctr = parseFloat(d.ctr || 0);
const cpc = parseFloat(d.cpc || 0);

// Extrair compras (purchase)
const actions = d.actions || [];
const purchases = actions.find(a => a.action_type === 'purchase');
const numCompras = purchases ? parseInt(purchases.value) : 0;

const costPerAction = d.cost_per_action_type || [];
const cpaPurchase = costPerAction.find(a => a.action_type === 'purchase');
const cpa = cpaPurchase ? parseFloat(cpaPurchase.value) : 0;

const receita = numCompras * 27; // preço eBook R$27
const roas = spend > 0 ? receita / spend : 0;

// Semáforos
const semaforo = (val, bom, atencao, invertido = false) => {
  if (!invertido) {
    if (val >= bom) return '✅';
    if (val >= atencao) return '⚠️';
    return '🔴';
  } else {
    if (val <= bom) return '✅';
    if (val <= atencao) return '⚠️';
    return '🔴';
  }
};

const sCTR = semaforo(ctr, 2.0, 1.0);
const sCPC = semaforo(cpc, 1.00, 1.50, true);
const sCPA = cpa > 0 ? semaforo(cpa, 15, 20, true) : '—';
const sROAS = roas > 0 ? semaforo(roas, 2.0, 1.35) : '—';

// Budget
const budgetDia = 33.00;
const percGasto = ((spend / budgetDia) * 100).toFixed(0);

// Alerta se algum KPI crítico
const alertas = [];
if (ctr < 1.0 && impressions > 1000) alertas.push('CTR muito baixo — revisar criativos');
if (cpc > 1.50) alertas.push('CPC alto — checar público e criativo');
if (cpa > 20 && numCompras > 0) alertas.push('CPA acima do limite — pausar ad set mais caro');
if (roas < 1.35 && numCompras > 0) alertas.push('ROAS abaixo do mínimo — avaliar pausa');

const hoje = new Date();
const ontem = new Date(hoje.getTime() - 24 * 60 * 60 * 1000);
const dataStr = ontem.toLocaleDateString('pt-BR');

let mensagem = `📊 RELATÓRIO DIÁRIO — Empresa Protegida™\n📅 ${dataStr}\n\n`;
mensagem += `💰 Gasto: R$${spend.toFixed(2)} / R$${budgetDia.toFixed(2)} (${percGasto}%)\n`;
mensagem += `📱 Impressões: ${impressions.toLocaleString('pt-BR')}\n`;
mensagem += `🖱️ Cliques: ${clicks.toLocaleString('pt-BR')}\n`;
mensagem += `📈 CTR: ${ctr.toFixed(2)}% ${sCTR}\n`;
mensagem += `💲 CPC: R$${cpc.toFixed(2)} ${sCPC}\n`;
mensagem += `🛒 Compras: ${numCompras}\n`;
mensagem += `💵 Receita estimada: R$${receita.toFixed(2)}\n`;
if (cpa > 0) mensagem += `📉 CPA: R$${cpa.toFixed(2)} ${sCPA}\n`;
if (roas > 0) mensagem += `🚀 ROAS: ${roas.toFixed(2)}x ${sROAS}\n`;

if (alertas.length > 0) {
  mensagem += `\n⚠️ AÇÕES NECESSÁRIAS:\n`;
  alertas.forEach(a => { mensagem += `• ${a}\n`; });
}

return [{ json: { mensagem, tem_alerta: alertas.length > 0 } }];
